<script setup lang="ts">import type { Agent,Message } from '../domain/types';import { speakerName } from '../domain/presentation';import MarkdownContent from './MarkdownContent.vue';import NpcAvatar from './NpcAvatar.vue';const props=defineProps<{messages:readonly Message[];agents:readonly Agent[];teamId:number;activeAgentId?:number|null}>();const fallback=(m:Message):Agent=>({id:m.senderId,teamId:0,name:speakerName(m.senderName),i18n:{},status:'idle'});const shownName=(m:Message)=>speakerName(m.senderName,props.agents.find(a=>a.id===m.senderId));const messageKey=(m:Message,index:number)=>m.id!=null?`message-${m.id}`:`message-${m.senderId}-${index}`;</script>
<template><ol class="dialogue" aria-label="讨论内容"><li v-if="!messages.length" class="empty-state">房内尚无对话，诸位先生正静候问道之声。</li><li v-for="(m,index) in messages" :id="messageKey(m,index)" :key="messageKey(m,index)" :class="{operator:m.senderId<0}"><NpcAvatar :agent="agents.find(a=>a.id===m.senderId)||fallback(m)" :status="m.senderId===activeAgentId?'speaking':'idle'" compact/><article><header><b>{{shownName(m)}}</b><time>{{m.sentAt ? new Date(m.sentAt).toLocaleString('zh-CN',{hour:'2-digit',minute:'2-digit'}) : ''}}</time><span v-if="m.immediate">急件</span></header><MarkdownContent :content="m.content" :team-id="teamId"/></article></li></ol></template>
